pub fn insert_after(&mut self, key: K, value: V) -> Result<(), UnorderedKeyError> {
    if let Some((prev, _)) = self.peek_prev() {
        if &key <= prev {
            return Err(UnorderedKeyError {});
        }
    }
    if let Some((next, _)) = self.peek_next() {
        if &key >= next {
            return Err(UnorderedKeyError {});
        }
    }
    unsafe {
        self.insert_after_unchecked(key, value);
    }
    Ok(())
}

